{
  "sentences": [
    {
      "text": "你應該早點睡覺。",
      "pinyin": "Nǐ yīnggāi zǎo diǎn shuìjiào.",
      "pinyin_numeric": "ni3 ying1gai1 zao3 dian3 shui4jiao4",
      "translation_en": "You should go to bed earlier.",
      "translation_ko": "너는 더 일찍 자야 해."
    },
    {
      "text": "我們必須遵守規定。",
      "pinyin": "Wǒmen bìxū zūnshǒu guīdìng.",
      "pinyin_numeric": "wo3men bi4xu1 zun1shou3 gui1ding4",
      "translation_en": "We must follow the rules.",
      "translation_ko": "우리는 규칙을 지켜야 합니다."
    },
    {
      "text": "你不需要買那麼多東西。",
      "pinyin": "Nǐ bù xūyào mǎi nàme duō dōngxī.",
      "pinyin_numeric": "ni3 bu4 xu1yao4 mai3 na4me duo1 dong1xi1",
      "translation_en": "You don't need to buy so many things.",
      "translation_ko": "너는 그렇게 많은 것을 살 필요가 없어."
    },
    {
      "text": "我建議你試試這個。",
      "pinyin": "Wǒ jiànyì nǐ shì shì zhège.",
      "pinyin_numeric": "wo3 jian4yi4 ni3 shi4 shi4 zhe4ge5",
      "translation_en": "I suggest you try this.",
      "translation_ko": "나는 네가 이것을 시도해 보는 것을 추천해."
    },
    {
      "text": "你最好帶雨傘，因為可能會下雨。",
      "pinyin": "Nǐ zuìhǎo dài yǔsǎn, yīnwèi kěnéng huì xiàyǔ.",
      "pinyin_numeric": "ni3 zui4hao3 dai4 yu3san3, yin1wei4 ke3neng2 hui4 xia4yu3",
      "translation_en": "You had better bring an umbrella because it might rain.",
      "translation_ko": "비가 올 수도 있으니 우산을 가져가는 게 좋아."
    },
    {
      "text": "你不應該在這裡抽煙。",
      "pinyin": "Nǐ bù yīnggāi zài zhèlǐ chōuyān.",
      "pinyin_numeric": "ni3 bu4 ying1gai1 zai4 zhe4li3 chou1yan1",
      "translation_en": "You shouldn't smoke here.",
      "translation_ko": "여기서 담배를 피우면 안 됩니다."
    },
    {
      "text": "你得先完成功課才能看電視。",
      "pinyin": "Nǐ děi xiān wánchéng gōngkè cáinéng kàn diànshì.",
      "pinyin_numeric": "ni3 dei3 xian1 wan2cheng2 gong1ke4 cai2neng2 kan4 dian4shi4",
      "translation_en": "You have to finish your homework first before watching TV.",
      "translation_ko": "숙제를 먼저 끝내야 텔레비전을 볼 수 있어."
    },
    {
      "text": "為了健康，你應該多吃水果。",
      "pinyin": "Wèile jiànkāng, nǐ yīnggāi duō chī shuǐguǒ.",
      "pinyin_numeric": "wei4le5 jian4kang1, ni3 ying1gai1 duo1 chi1 shui3guo3",
      "translation_en": "For your health, you should eat more fruit.",
      "translation_ko": "건강을 위해 과일을 더 많이 먹어야 해."
    },
    {
      "text": "你必須準時到，不然會錯過火車。",
      "pinyin": "Nǐ bìxū zhǔnshí dào, bùrán huì cuòguò huǒchē.",
      "pinyin_numeric": "ni3 bi4xu1 zhun3shi2 dao4, bu4ran2 hui4 cuo4guo4 huo3che1",
      "translation_en": "You must arrive on time, otherwise you'll miss the train.",
      "translation_ko": "정시에 도착해야 해, 그렇지 않으면 기차를 놓칠 거야."
    },
    {
      "text": "你不必擔心，我會幫你。",
      "pinyin": "Nǐ bùbì dānxīn, wǒ huì bāng nǐ.",
      "pinyin_numeric": "ni3 bu4bi4 dan1xin1, wo3 hui4 bang1 ni3",
      "translation_en": "You don't have to worry; I'll help you.",
      "translation_ko": "걱정할 필요 없어, 내가 도와줄게."
    }
  ]
}
